#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
  float weight;
  long assign;
  float cost;
} Point_Struct;

__kernel void pgain_kernel(
    __global Point_Struct* p,
    __global float* coord,
    __global float* work_mem,
    __global int* center_table,
    __global char* switch_membership,
    const int num,
    const int dim,
    const long x,
    const int stride,
    const int K)
{
    int i = get_global_id(0);
    if (i >= num) return;

    float x_cost = 0.0f;
    float current_cost = 0.0f;
    int assign = 0;

    // Compute squared distance between p[i] and p[x]
    float dist_val = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[i + d * num] - coord[x + d * num];
        dist_val += diff * diff;
    }
    x_cost = dist_val * p[i].weight;
    current_cost = p[i].cost;
    assign = p[i].assign;

    if (x_cost < current_cost) {
        switch_membership[i] = 1;
        // Accumulate cost difference in work_mem for this thread
        // Use atomic add to avoid race conditions
        atomic_add(&work_mem[i * stride + K + 1], x_cost - current_cost);
    } else {
        // Accumulate cost difference for assigned center
        int center_idx = center_table[assign];
        atomic_add(&work_mem[center_idx + i * stride], current_cost - x_cost);
    }
}

